-- GarmentIQ Customers Import - PostgreSQL / pgAdmin
-- Source: GarmentIQ_Customers.csv
-- Run this BEFORE orders, order_items, and sales.

BEGIN;

TRUNCATE TABLE sales, order_items, orders, customers RESTART IDENTITY CASCADE;


SELECT setval(pg_get_serial_sequence('customers', 'customer_id'), COALESCE(MAX(customer_id), 1), true) FROM customers;

COMMIT;
